/**
 * Get the translated label for a specific major (code_fil), with graceful
 * fallback to the raw CSV text if a code hasn't been catalogued yet
 * (e.g. a brand-new 2026 filiere not present in the source data used to
 * build this dictionary).
 */
export function getFiliereLabel(lang, codeFil, fallbackRaw) {
  const entry = FILIERE_LABELS[codeFil]
  if (!entry) return fallbackRaw
  return entry[lang] || entry.fr || fallbackRaw
}